const seen = new Set();
const queries = [];
const resolveItems = $('Resolve Tags').all();

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const category = resolveItems[i]?.json?.category || '';

  let tags;
  try {
    tags = JSON.parse(item.json.data || '[]');
  } catch {
    continue;
  }

  if (!Array.isArray(tags) || tags.length === 0) continue;

  const tag = tags.find(t =>
    t.name.toLowerCase() === category.toLowerCase()
  ) || tags[0];

  if (!seen.has(tag.id)) {
    seen.add(tag.id);
    queries.push({ json: { tagId: tag.id, tagName: tag.name, category } });
  }
}

return queries;

const source = 'euremotejobs';
const seen = new Set();
const jobs = [];

// Build tagId -> category map from Build Queries
const queryItems = $('Build Queries').all();
const tagToCategory = {};
for (const q of queryItems) {
  tagToCategory[q.json.tagId] = q.json.category;
}

for (const item of $input.all()) {
  const wp = item.json;
  if (!wp.link || seen.has(wp.link)) continue;
  seen.add(wp.link);

  const terms = wp._embedded?.['wp:term'] || [];
  const allTerms = terms.flat();
  const regions = allTerms.filter(t => t.taxonomy === 'job_listing_region');
  const location = regions.map(r => r.name).join(', ') || null;

  // Find category by matching WP tags to Build Queries tagId map
  const wpTags = allTerms.filter(t => t.taxonomy === 'job_listing_tag');
  const category = wpTags.map(t => tagToCategory[t.id]).find(c => c) || '';

  jobs.push({
    title: wp.title?.rendered || '',
    company: wp.meta?._company_name || null,
    url: wp.link,
    description: wp.content?.rendered || '',
    source,
    salary: null,
    location,
    remote: true,
    publishedAt: wp.date || null,
    rawData: wp,
    category,
  });
}

return [{ json: { body: jobs, count: jobs.length, source } }];

const err = $input.first().json;
const source = $('Set Source').first().json.source;
const msg = err.error?.message || err.message || 'Unknown error';
return [{json: {level: 'error', message: `${$workflow.name}: ${msg}`, source}}];
